import sys

def hamming(a, b):
    return (a ^ b).bit_count()

class Node:
    __slots__ = ("val", "children")
    def __init__(self, val):
        self.val = val
        self.children = {}

def insert(node, x):
    d = hamming(x, node.val)
    child = node.children.get(d)
    if child is None:
        node.children[d] = Node(x)
    else:
        insert(child, x)

def query(node, x, best):
    d = hamming(x, node.val)
    if d < best:
        best = d
        if best == 0:
            return 0
    lo = d - best
    if lo < 0:
        lo = 0
    hi = d + best
    for dist, child in node.children.items():
        if lo <= dist <= hi:
            cand = query(child, x, best)
            if cand < best:
                best = cand
                if best == 0:
                    return 0
    return best

